1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	const isNeighbor = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
5	  Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1 && !(nx === x && ny === y);
6	
7	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
8	  const countLiveNeighbors = (cell: Cell): number =>
9	    liveCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	  const isAlive = ([x, y]: Cell): boolean =>
12	    liveCells.some(([lx, ly]) => lx === x && ly === y);
13	
14	  const survivors = liveCells.filter((cell) => countLiveNeighbors(cell) === 3);
15	
16	  const born: Cell[] = [];
17	  const seen = new Set<string>();
18	  for (const [x, y] of liveCells) {
19	    for (let dx = -1; dx <= 1; dx++) {
20	      for (let dy = -1; dy <= 1; dy++) {
21	        const candidate: Cell = [x + dx, y + dy];
22	        const key = `${candidate[0]},${candidate[1]}`;
23	        if (seen.has(key)) continue;
24	        seen.add(key);
25	        if (!isAlive(candidate) && countLiveNeighbors(candidate) === 3) {
26	          born.push(candidate);
27	        }
28	      }
29	    }
30	  }
31	
32	  return [...survivors, ...born];
33	};
